class LFUCache {
    class Node {
        int key, value, count;
        Node prev, next;
        Node(int k, int v) {
            key = k;
            value = v;
            count = 1;
        }
    }

    class DLinkedList {
        Node head, tail;
        DLinkedList() {
            head = new Node(0, 0);
            tail = new Node(0, 0);
            head.next = tail;
            tail.prev = head;
        }
        void addNode(Node node) {
            node.prev = head;
            node.next = head.next;
            head.next.prev = node;
            head.next = node;
        }
        void removeNode(Node node) {
            Node prev = node.prev, next = node.next;
            prev.next = next;
            next.prev = prev;
        }
        Node removeLast() {
            if (head.next == tail) return null;
            Node last = tail.prev;
            removeNode(last);
            return last;
        }
    }

    int capacity, size;
    Map<Integer, Node> keyNode;
    Map<Integer, DLinkedList> countList;
    int minCount;

    public LFUCache(int capacity) {
        this.capacity = capacity;
        size = 0;
        keyNode = new HashMap<>();
        countList = new HashMap<>();
        minCount = 0;
    }

    public int get(int key) {
        if (!keyNode.containsKey(key)) return -1;
        Node node = keyNode.get(key);
        updateCount(node);
        return node.value;
    }

    public void put(int key, int value) {
        if (capacity == 0) return;
        if (keyNode.containsKey(key)) {
            Node node = keyNode.get(key);
            node.value = value;
            updateCount(node);
        } else {
            if (size == capacity) {
                DLinkedList list = countList.get(minCount);
                Node node = list.removeLast();
                keyNode.remove(node.key);
                countList.get(minCount).removeNode(node);
                if (countList.get(minCount).head.next == countList.get(minCount).tail) {
                    countList.remove(minCount);
                    minCount++;
                }
                size--;
            }
            Node node = new Node(key, value);
            keyNode.put(key, node);
            DLinkedList list = countList.getOrDefault(1, new DLinkedList());
            list.addNode(node);
            countList.put(1, list);
            minCount = 1;
            size++;
        }
    }

    void updateCount(Node node) {
        DLinkedList list = countList.get(node.count);
        list.removeNode(node);
        if (list.head.next == list.tail && node.count == minCount) {
            minCount++;
        }
        node.count++;
        DLinkedList newList = countList.getOrDefault(node.count, new DLinkedList());
        newList.addNode(node);
        countList.put(node.count, newList);
    }
}
